import{_ as t,o as a,c as r,a2 as i}from"./chunks/framework.DSLFjWWy.js";const p=JSON.parse('{"title":"What Is AOSC?","description":"","frontmatter":{},"headers":[],"relativePath":"get-started/what-is-aosc.md","filePath":"get-started/what-is-aosc.md","lastUpdated":1781637126000}'),o={name:"get-started/what-is-aosc.md"};function s(n,e,l,d,c,u){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="what-is-aosc" tabindex="-1">What Is AOSC? <a class="header-anchor" href="#what-is-aosc" aria-label="Permalink to &quot;What Is AOSC?&quot;">​</a></h1><p>AOSC is an OpenSearch plugin for online index migration. It is designed for cases where the target index needs a different schema, shard layout, or document shape than the source index.</p><p>AOSC does not modify an index in place. You create a new target index, then AOSC copies and replays source data into it before swapping an alias.</p><div class="tip custom-block"><p class="custom-block-title">In one sentence</p><p>AOSC is for same-cluster migrations where the old index must keep serving traffic while a new index is populated and prepared for alias cutover.</p></div><h2 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h2><p>OpenSearch supports some mapping additions, but many schema and layout changes require a new index. A plain <code>_reindex</code> copies a point-in-time view of the source. If the source keeps receiving writes, you need a second process to replay or reconcile writes that happened during the copy.</p><p>AOSC provides that replay and cutover workflow inside the cluster.</p><h2 id="migration-flow" tabindex="-1">Migration Flow <a class="header-anchor" href="#migration-flow" aria-label="Permalink to &quot;Migration Flow&quot;">​</a></h2><p>AOSC follows a guarded migration path:</p><ol><li>Validate the source, target, alias, and options.</li><li>Backfill existing source documents into the target.</li><li>Replay source operation history while writes continue on the source.</li><li>Wait until every source-primary shard is close enough to cut over.</li><li>Briefly write-block the source, replay the final operations, validate counts, and swap the alias.</li></ol><p>For the interactive phase-by-phase view, see <a href="./../how-it-works">How AOSC Works</a>.</p><div class="info custom-block"><p class="custom-block-title">Key invariant</p><p>Applications should talk to the alias, not directly to the concrete source index. Without an alias, AOSC cannot complete the cutover safely.</p></div><h2 id="vocabulary" tabindex="-1">Vocabulary <a class="header-anchor" href="#vocabulary" aria-label="Permalink to &quot;Vocabulary&quot;">​</a></h2><div class="aosc-table-scroll"><table class="aosc-table"><thead><tr><th>Term</th><th>Meaning</th></tr></thead><tbody><tr><td>Source index</td><td>The current index that holds live data.</td></tr><tr><td>Target index</td><td>The pre-created index with the desired mappings, settings, and shard count.</td></tr><tr><td>Alias</td><td>The application-facing name AOSC swaps from source to target at cutover.</td></tr><tr><td>Backfill</td><td>Copy of existing source documents into the target.</td></tr><tr><td>Replay</td><td>Applying source-shard operation history to the target.</td></tr><tr><td>Convergence</td><td>A shard is close enough to the source global checkpoint to proceed toward cutover.</td></tr><tr><td>Cutover</td><td>Write-block source, replay final operations, validate, and swap the alias.</td></tr><tr><td>Shard worker</td><td>Per-source-primary worker that performs backfill and replay.</td></tr><tr><td>Coordinator</td><td>Cluster-manager-side service that advances migration phases.</td></tr></tbody></table></div><h2 id="required-assumptions" tabindex="-1">Required Assumptions <a class="header-anchor" href="#required-assumptions" aria-label="Permalink to &quot;Required Assumptions&quot;">​</a></h2><ul><li>The source and target are in the same OpenSearch cluster.</li><li>The target index already exists.</li><li>Applications use an alias that can be moved from source to target.</li><li>Applications retry writes that are rejected during the cutover write block.</li><li>The plugin is installed at the same version on all cluster nodes.</li></ul><h2 id="limitations-to-understand-first" tabindex="-1">Limitations to Understand First <a class="header-anchor" href="#limitations-to-understand-first" aria-label="Permalink to &quot;Limitations to Understand First&quot;">​</a></h2><ul><li>AOSC is not zero-interruption. Source writes are blocked briefly during cutover. Successful production cutovers have been observed where the application-visible write interruption was about 2 seconds to 30 seconds, including a 50 TB index at about 30 seconds. This is an observation, not an upper bound; validation, alias update, cluster-manager responsiveness, shard count, and write load can make specific runs shorter or longer.</li><li>AOSC does not delete the source or target index for you after a migration.</li><li>Cross-cluster migrations are not supported.</li><li>Custom routing and shard count changes require careful review; some routes require explicit data-loss consent.</li><li>Built-in document transforms use OpenSearch update-script style and are currently 1:1 for each source document.</li></ul><div class="warning custom-block"><p class="custom-block-title">Plan retries before production</p><p>Treat write retry behavior as a production readiness requirement, not an implementation detail. The plugin can coordinate the migration, but the application must tolerate the brief write block.</p></div><p>See <a href="./../reference/known-limitations">Known Limitations</a> before planning a real migration.</p>',20)])])}const m=t(o,[["render",s]]);export{p as __pageData,m as default};
